
import os
import time
from datetime import datetime
from urllib.parse import urljoin

import requests
from flask import Flask, Response, jsonify

app = Flask(__name__)

RETAIL_TOTAL = int(os.getenv("RETAIL_TOTAL", "41750000"))
HOME_SERVER_URL = os.getenv("HOME_SERVER_URL", "").strip().rstrip("/")
HOME_SERVER_TOKEN = os.getenv("HOME_SERVER_TOKEN", "").strip()
FETCH_TIMEOUT = float(os.getenv("FETCH_TIMEOUT", "8"))
CACHE_SECONDS = float(os.getenv("CACHE_SECONDS", "3"))
HISTORY_SECONDS = 5 * 60 * 60

_session = requests.Session()
_cache = {"at": 0.0, "payload": None}
_history = []
_next_snapshot_bucket = None


def _next_full_hour_bucket(epoch: float) -> int:
    current = _hour_bucket(epoch)
    return current + 3600


def _append_snapshot(payload: dict) -> None:
    """
    Refresh-ul vizual ramane la 5 secunde, dar snapshot-urile se salveaza
    doar din ora in ora. La prima pornire nu etichetam valoarea curenta cu
    o ora trecuta. Prima salvare va fi la ora fixa urmatoare, apoi cate una
    la fiecare ora.
    """
    global _next_snapshot_bucket

    now = time.time()
    subscribed = _as_int(payload.get("subscribed"))
    if subscribed <= 0:
        return

    if _next_snapshot_bucket is None:
        _next_snapshot_bucket = _next_full_hour_bucket(now)
        return

    if now < _next_snapshot_bucket:
        return

    item = {
        "epoch": now,
        "bucket": _next_snapshot_bucket,
        "time": _hour_label(_next_snapshot_bucket),
        "subscribed": subscribed,
        "percentage": round((subscribed / RETAIL_TOTAL) * 100, 2) if RETAIL_TOTAL else 0,
    }

    if _history and _history[-1].get("bucket") == item["bucket"]:
        _history[-1] = item
    else:
        _history.append(item)

    while _next_snapshot_bucket <= now:
        _next_snapshot_bucket += 3600

    while len(_history) > 5:
        _history.pop(0)


def _snapshots_for_response():
    return [
        {
            "time": x["time"],
            "subscribed": x["subscribed"],
            "percentage": x["percentage"],
        }
        for x in sorted(_history, key=lambda x: x.get("bucket", 0))[-5:]
    ]

def _fetch_from_home() -> dict:
    url = _home_data_url()
    if not url:
        return {
            "ok": False,
            "subscribed": 0,
            "percentage": 0,
            "timestamp": "—",
            "source": "render",
            "retail_total": RETAIL_TOTAL,
            "available": RETAIL_TOTAL,
            "snapshots": _snapshots_for_response(),
            "error": "Lipseste HOME_SERVER_URL in Render Environment.",
        }

    headers = {"Accept": "application/json", "User-Agent": "TRIP-Gauge-Render/2.0"}
    if HOME_SERVER_TOKEN:
        headers["X-API-Key"] = HOME_SERVER_TOKEN
        headers["X-TRIP-Token"] = HOME_SERVER_TOKEN

    try:
        r = _session.get(url, headers=headers, timeout=FETCH_TIMEOUT)
        r.raise_for_status()
        data = r.json()
        subscribed = _as_int(data.get("subscribed") or data.get("bid_vol") or data.get("bidVol"))
        percentage = round((subscribed / RETAIL_TOTAL) * 100, 2) if RETAIL_TOTAL else 0
        available = max(RETAIL_TOTAL - subscribed, 0)
        payload = {
            "ok": bool(data.get("ok", True)) and subscribed >= 0,
            "subscribed": subscribed,
            "percentage": percentage,
            "timestamp": data.get("timestamp") or data.get("updated_at") or _now_label(),
            "source": "home_server",
            "home_source": data.get("source", "BVB"),
            "retail_total": RETAIL_TOTAL,
            "available": available,
            "price": "2,135 lei",
            "error": data.get("error"),
        }
        _append_snapshot(payload)
        payload["snapshots"] = _snapshots_for_response()
        return payload
    except Exception as exc:
        last_payload = _cache.get("payload")
        if last_payload:
            fallback = dict(last_payload)
            fallback["ok"] = False
            fallback["source"] = "render_cache"
            fallback["snapshots"] = _snapshots_for_response()
            fallback["error"] = f"Nu pot citi serverul de acasa: {exc}"
            return fallback
        return {
            "ok": False,
            "subscribed": 0,
            "percentage": 0,
            "timestamp": "—",
            "source": "render",
            "retail_total": RETAIL_TOTAL,
            "available": RETAIL_TOTAL,
            "snapshots": _snapshots_for_response(),
            "error": f"Nu pot citi serverul de acasa: {exc}",
        }


@app.get("/health")
def health():
    return jsonify({
        "ok": True,
        "home_server_configured": bool(HOME_SERVER_URL),
        "home_data_url": _home_data_url() if HOME_SERVER_URL else None,
        "snapshots_kept_hours": 5,
    })


@app.get("/api/data")
@app.get("/data")
def data():
    now = time.time()
    if _cache["payload"] is not None and now - _cache["at"] < CACHE_SECONDS:
        cached = dict(_cache["payload"])
        cached["snapshots"] = _snapshots_for_response()
        return jsonify(cached)
    payload = _fetch_from_home()
    _cache["payload"] = payload
    _cache["at"] = now
    return jsonify(payload)


